"""Megatron-LM configuration schema (auto-generated)."""

from dataclasses import dataclass, field
from typing import Any, Literal
from compoconf import ConfigInterface

@dataclass
class MegatronConfig(ConfigInterface):
    """Typed projection of Megatron-LM CLI arguments."""
    # Generated by scripts/generate_megatron_dataclass.py
    # Intra-layer model parallelism. Splits tensors across GPU ranks.
    tensor_model_parallel_size: int = 1

    # Configuring backend option of pipeline parallel communication (e.g., nccl, ucc) If None,
    # the default backend will be used.
    pipeline_model_parallel_comm_backend: Literal['nccl', 'ucc'] | None = None

    # Inter-layer model parallelism. Splits transformer layers across GPU ranks.
    pipeline_model_parallel_size: int = 1

    # Makes tensor parallelism more memory efficient for LLMs (20B+) by parallelizing layer
    # norms and dropout sequentially. See Reducing Activation Recomputation in Large
    # Transformer Models (https://arxiv.org/abs/2205.05198) for more details.
    sequence_parallel: bool = False

    # Splits network input along sequence dimension across GPU ranks.
    context_parallel_size: int = 1

    # Degrees of the hierarchical context parallelism. Users should provide a list to specify
    # the sizes for different levels. Taking the a2a+p2p cp comm type as example, it contains
    # groups of two levels, so the first value of the list indicates the group size of the a2a
    # communication type, and the second value indicates the group size of the p2p
    # communication type.
    hierarchical_context_parallel_sizes: list[int] | None = None

    # Maximum sequence length per DPxCP rank. This is the maximum sequence length each rank
    # can handle without overflowing the memory. Typically, a good starting point is to set
    # this to maximum sequence length / context parallel size. This is used to calculate the
    # number and length of sub-samples assigned to each rank when using
    # hybrid_context_parallel.
    max_seqlen_per_dp_cp_rank: int | None = None

    # If true, enables hybrid context parallel. This is used to balance the workload of each
    # CP rank when we use packed samples with variable sequence lengths. Please set
    # max_seqlen_per_dp_cp_rank when using hybrid_context_parallel.
    hybrid_context_parallel: bool = False

    # Distributes Moe Experts across sub data parallel dimension.
    expert_model_parallel_size: int = 1

    # Intra-layer tensor model parallelism for expert layer. Splits tensors across GPU ranks.
    # Default is None, which will be set to the value of tensor_model_parallel_size.
    expert_tensor_parallel_size: int | None = None

    # Controls weights initialization. This option can be useful when you know you are going
    # to load values from a checkpoint.
    perform_initialization: bool = True

    # When set to False, we initialize the weights directly on the GPU. CPU initialization is
    # the same regardless of tensor model parallelism, but GPU initialization is not.
    # Transferring weights from CPU to GPU can take a significant amount of time for large
    # models.
    use_cpu_initialization: bool | None = None

    # If true, train with fp16 mixed precision training.
    fp16: bool = False

    # If true, train with bf16 mixed precision training.
    bf16: bool = False

    # If true, code that has deterministic execution will be chosen. This usually means slower
    # execution, but is good for debugging and testing. Defaults to False.
    deterministic_mode: bool = False

    # If true, allows overlapping of Linear layer execution with tensor parallel communication
    # collectives like AllGather/ReduceScatter. Overlapping is done for the linear layers
    # wherever possible during the forward and the backward pass.
    tp_comm_overlap: bool = False

    # Controls All-Gather overlap with Bprop activation gradient GEMM. Don't care if
    # tp_comm_overlap is False.
    tp_comm_bulk_wgrad: bool = True

    # Controls Reduce-Scatter overlap with Bprop weight gradient GEMM. Don't care if
    # tp_comm_overlap is False.
    tp_comm_bulk_dgrad: bool = True

    # Controls All-Gather overlap with GEMM by pipelining the GEMM and All-Gather. Don't care
    # if tp_comm_overlap is False.
    tp_comm_overlap_ag: bool = True

    # Controls Reduce-Scatter overlap with GEMM by pipelining the GEMM and Reduce-Scatter.
    # Don't care if tp_comm_overlap is False.
    tp_comm_overlap_rs: bool = True

    # If true, allows Reduce-Scatter overlap with DGRAD GEMM by pipelining the GEMM and
    # Reduce-Scatter splits. Don't care if tp_comm_overlap is False.
    tp_comm_overlap_rs_dgrad: bool = False

    # Deprecated from TransformerEngine v1.6.0. Controls All-Gather overlap with Fprop GEMM by
    # pipelining the GEMM and All-Gather splits. Don't care if tp_comm_overlap is False.
    tp_comm_split_ag: bool = True

    # Deprecated from TransformerEngine v1.6.0. Controls Reduce-Scatter overlap with Fprop
    # GEMM by pipelining the GEMM and Reduce-Scatter splits. Don't care if tp_comm_overlap is
    # False.
    tp_comm_split_rs: bool = True

    # If this is enabled, the fused cross entropy implementation would be used. Defaults to
    # False.
    cross_entropy_loss_fusion: bool = False

    # If 'native', MCore based CE loss fusion is used, if 'te', Parallel CE loss from
    # Transformer Engine library is used. Defaults to 'native'.
    cross_entropy_fusion_impl: Literal['native', 'te'] = 'native'

    # Set the bootstrapping backend of Tensor parallel communications.
    tp_comm_bootstrap_backend: Literal['nccl', 'mpi', 'gloo'] = 'nccl'

    # Overlap EP A2A communications with independent computations of different micro-batches
    # in 1f1b phase of pipelining or non-pipelining schedule.
    overlap_moe_expert_parallel_comm: bool = False

    # Delay the weight gradient computation to improve batch-level communication overlapping
    delay_wgrad_compute: bool = False

    # Delay the weight gradient computation for TE Grouped GEMM MoE experts. When enabled with
    # FSDP, the expert weight gradients are computed on a separate CUDA stream after the data
    # gradients finish, allowing overlap of wgrad compute with EP A2A communication. The FSDP
    # gradient reduce-scatter for expert parameters is deferred until the delayed wgrad
    # computation completes. This requires transformer_engine with GroupedLinear support (TE
    # >= 2.3.0).
    overlap_dispatch_backward_with_experts_wgrad: bool = False

    # Enable early memory release of attention activations during EP overlap. EP overlap can
    # increase peak memory usage when the overlapped forward module allocates more memory than
    # what is freed by the backward module. This flag addresses this by reordering the
    # attention backward pass to occur earlier in the schedule. Specifically: - Without this
    # flag: attn_bwd executes after moe_combine_fwd - With this flag: attn_bwd executes before
    # mlp_fwd The earlier execution releases attention activations sooner, reducing peak
    # memory. Note: This may impact performance as moe_combine_fwd and moe_dispatch_bwd become
    # exposed (not overlapped with other computation).
    ep_overlap_early_attn_memory_release: bool = False

    # Use custom ring_exchange kernel instead of torch.distributed.batch_isend_irecv().
    # Requires custom built torch with torch.distributed.ring_exchange.
    use_ring_exchange_p2p: bool = False

    # If true, defers the embedding WGRAD GEMMs while pipeline flush is taking place enabling
    # us to hide pipeline flush latency. Defaults to False.
    defer_embedding_wgrad_compute: bool = False

    # This value tunes the number of micro-batches for which the embedding weight gradient
    # compute needs to be deferred to pipeline flush, this argument is invalid if
    # `defer_embedding_wgrad_compute` is False. Defaults to 0, which means all micro-batches
    # are deferred.
    wgrad_deferral_limit: int = 0

    # If true, overlap communication and computation in warm up and flush phase. Only valid
    # when overlap_p2p_comm is True and batch_p2p_comm is False. Defaults to False.
    overlap_p2p_comm_warmup_flush: bool = False

    # This value specifies the number of micro-batches that are executed at a time for a given
    # virtual stage (both forward and backward). Default (in __post_init__() method below) to
    # pipeline_parallel_size which specifies a depth-first schedule. Example: for PP=2 VP=2,
    # when microbatch_group_size_per_vp_stage=2, num_microbatches = 4, we have rank 0 | 0 1 0
    # 1 2 3 2 3 rank 1 | 0 1 0 1 2 3 2 3 When microbatch_group_size_per_vp_stage=3,
    # num_microbatches = 5, we have rank 0 | 0 1 2 0 1 2 3 4 3 4 rank 1 | 0 1 2 0 1 2 3 4 3 4
    microbatch_group_size_per_vp_stage: int | None = None

    # This will be set automatically according to the pipeline layout, and will be set to True
    # if MTP is in a separate vpp stage.
    mtp_standalone: bool = False

    # Tells the number of transformer layers for which activations has to be offloaded.
    cpu_offloading_num_layers: int = 0

    # If True, the pinned CPU buffers are retained after offloading and reused for the next
    # iteration. It is useful for cuda graphs capture.
    cpu_offloading_retain_pinned_cpu_buffers: bool = False

    # Number of transformer layers in a transformer block.
    num_layers: int | None = None

    # Number of Multi-Token Prediction (MTP) Layers. MTP extends the prediction scope to
    # multiple future tokens at each position. This MTP implementation sequentially predict
    # additional tokens by using D sequential modules to predict D additional tokens.
    mtp_num_layers: int | None = None

    # Weighting factor of Multi-Token Prediction (MTP) loss. We compute the average of the MTP
    # losses across all depths, and multiply it the scaling factor to obtain the overall MTP
    # loss, which serves as an additional training objective.
    mtp_loss_scaling_factor: float = 0.1

    # Use a single MTP layer repeatedly instead of multiple separate layers.
    mtp_use_repeated_layer: bool = False

    # DEPRECATED: Use unified hybrid_layer_pattern instead. Legacy argument for loading old
    # checkpoints. Force a specific hybrid layer pattern for MTP layers.
    mtp_hybrid_override_pattern: str | None = None

    # If set, the embedding layer will be treated as a standard transformer layer in the
    # context of partition and placement for pipeline parallelism.
    account_for_embedding_in_pipeline_split: bool = False

    # If set, the loss layer will be treated as a standard transformer layer in the context of
    # partition and placement for pipeline parallelism.
    account_for_loss_in_pipeline_split: bool = False

    # Transformer hidden size.
    hidden_size: int | None = None

    # Number of transformer attention heads.
    num_attention_heads: int | None = None

    # Attention backend to run. By default we let transformer engine decide the best backend
    # to run (except in the case of local). If attention backend is local we use the local
    # pytorch implementation in mcore. Users can specify exact backend by changing this
    # config.
    attention_backend: str = 'auto'

    # Applies modified softmax from https://www.evanmiller.org/attention-is-off-by-one.html.
    # Supports both TE FusedAttention and local unfused attention. Supports both a fixed
    # offset and and learnable offset.
    softmax_type: Literal['vanilla', 'off-by-one', 'learnable'] = 'vanilla'

    # Number of query groups for group query attention. If None, normal attention is used.
    num_query_groups: int = 1

    # Transformer Feed-Forward Network hidden size. This is set to 4*hidden_size if not
    # provided.
    ffn_hidden_size: int | None = None

    # Projection weights dimension in multi-head attention. This is set to hidden_size //
    # num_attention_heads if not provided.
    kv_channels: int | None = None

    # Dropout probability for transformer hidden state.
    hidden_dropout: float = 0.1

    # Post attention dropout probability.
    attention_dropout: float = 0.1

    # If true, move residual connections to fp32.
    fp32_residual_connection: bool = False

    # If True, uses the original BERT residule connection ordering.
    apply_residual_connection_post_layernorm: bool = False

    # Epsilon value for any LayerNorm/RMSNorm operations.
    layernorm_epsilon: float = 1e-05

    # If set to True, the LayerNorm is adjusted to center the gamma values around 0. This
    # improves numerical stability.
    layernorm_zero_centered_gamma: bool = False

    # Include/exclude a bias term in all linear layers (QKV projections, after core attention,
    # and two in MLP layer).
    add_bias_linear: bool = True

    # Add a bias term only for QKV projections.
    add_qkv_bias: bool = False

    # Offset term in the GLU activation function: activation_func(x[0]) * (x[1] + offset).
    # Only used when gated_linear_unit is True
    glu_linear_offset: float = 0.0

    # Clamp the output of the linear_fc1 in the activation function. Only used when
    # activation_func is quick_gelu.
    activation_func_clamp_value: float | None = None

    # True is rotate pairs of even and odd dimensions (RoFormer style), False is rotate pairs
    # of first half and second half (LLaMa style). Default to False.
    rotary_interleaved: bool = False

    # Which norm to use for normalization layers, valid options are `LayerNorm` and `RMSNorm`.
    normalization: Literal['LayerNorm', 'RMSNorm'] = 'LayerNorm'

    # Whether to apply `normalization` type of normalization to the query and key embeddings.
    qk_layernorm: bool = False

    # Whether to apply llama 4-style qk L2 norm.
    qk_l2_norm: bool = False

    # Whether to clip the query and key weights. Needed for Muon MLA Model training.
    qk_clip: bool = False

    # The balancing alpha for qk-clip. Q = Q * (eta ** alpha)
    qk_clip_alpha: float = 0.5

    # The balancing threshold for qk-clip. eta = min(threshold / max_attention_logits, 1.0)
    qk_clip_threshold: float = 100

    # Whether to apply output gate to the attention layers.
    attention_output_gate: bool = False

    # Whether cross entropy loss is calculated over the actual number of non-padded tokens in
    # the global batch, versus the default behavior of assuming all tokens are non-padded.
    calculate_per_token_loss: bool = False

    # Whether to use multi-latent attention.
    multi_latent_attention: bool = False

    # Type of attention variant to use. Currently support gated_delta_net and dsa.
    experimental_attention_variant: Literal['gated_delta_net', 'dsa'] | None = None

    # Number of DSA indexer heads.
    dsa_indexer_n_heads: int | None = None

    # Dimension per DSA indexer head.
    dsa_indexer_head_dim: int | None = None

    # Number of top-k tokens to select in DSA indexer.
    dsa_indexer_topk: int | None = None

    # Coefficient for the DSA indexer KL divergence loss. Set to 0 to disable indexer loss.
    dsa_indexer_loss_coeff: float | None = None

    # Whether to use sparse DSA indexer loss. If True, the indexer loss will be computed using
    # the top-k indices.
    dsa_indexer_use_sparse_loss: bool = False

    # Conv kernel dimension for the gated delta net.
    linear_conv_kernel_dim: int = 4

    # Query and key head dimension for the gated delta net.
    linear_key_head_dim: int = 128

    # Value and gate head dimension for the gated delta net.
    linear_value_head_dim: int = 128

    # Number of query and key heads for the gated delta net.
    linear_num_key_heads: int = 16

    # Number of value and gate heads for the gated delta net.
    linear_num_value_heads: int = 32

    # Standard deviation of the zero mean normal for the default initialization method, not
    # used if init_method and output_layer_init_method are provided.
    init_method_std: float = 0.02

    # Standard deviation of the zero mean normal for the default initialization method for the
    # embedding layer. If None, will be set to init_method_std. Setting this to a value around
    # 1.0 may avoid loss spikes in training. Setting this to any value will also skip applying
    # weight decay on embedding weights to avoid shrinkage towards zero. See
    # https://arxiv.org/abs/2312.16903 for more details.
    embedding_init_method_std: float | None = None

    # If True, initializes the model with the meta device. This is helpful for training of
    # very large models. This feature is only works when megatron fsdp is turned on.
    init_model_with_meta_device: bool = False

    # Enable Maximal Update Parameterization (MuP) for hyperparameter transfer across model
    # widths. When enabled, learning rates and initialization are scaled according to the
    # width multiplier to ensure consistent training dynamics.
    use_mup: bool = False

    # Width multiplier for MuP scaling, computed as hidden_size / mup_base_hidden_size. This
    # value is automatically computed in __post_init__ when use_mup is enabled.
    mup_width_mult: float = 1.0

    # Base hidden size for MuP width scaling. This is the reference width from which scaling
    # factors are computed. Defaults to hidden_size if not specified (base model case where
    # width_mult=1.0). Set this to your base/proxy model's hidden size when scaling up.
    mup_base_hidden_size: int | None = None

    # Multiplier for embedding layer output. Applied after the embedding lookup. Default: 1.0
    # (no scaling).
    mup_embedding_mult: float = 1.0

    # Multiplier for output logits before softmax. When MuP is enabled and this is left at
    # 1.0, it is auto-set to 1/mup_width_mult to keep output variance stable across widths.
    # Override to customize output scaling. Default: 1.0.
    mup_output_mult: float = 1.0

    # Base head dimension for MuP attention scaling. When set, softmax_scale =
    # sqrt(mup_base_head_dim) / (kv_channels ** mup_attn_scale_power). Set to base model's
    # d_head (e.g., 64) to match standard 1/sqrt(d_head) scaling at the base width, ensuring
    # non-MuP compatibility for that specific value.
    mup_base_head_dim: float | None = None

    # Power for attention scaling: softmax_scale = 1 / (kv_channels ** mup_attn_scale_power).
    # 0.5 = standard attention (1/sqrt(d_head)), 1.0 = MuP attention (1/d_head). Default: 1.0
    # (MuP scaling when use_mup is True). Set to 0.5 for standard scaling.
    mup_attn_scale_power: float = 1.0

    # If true, scale Q * K^T by 1 / layer-number. This improve numeric stability when training
    # with fp16. Also sets `attention_softmax_in_fp32` to True.
    apply_query_key_layer_scaling: bool = False

    # If True, sets torch.backends.cuda.matmul.allow_bf16_reduced_precision_reduction=False to
    # prevent matmul from using reduced precision accumulation when using BF16.
    disable_bf16_reduced_precision_matmul: bool = False

    # If True, uses fused weighted squared relu kernel when using MoE.
    use_fused_weighted_squared_relu: bool = False

    # If True, fuses residual connection and RMSNorm backward pass when TE is used.
    fused_residual_rmsnorm: bool = False

    # Determines which type of activation recompute to use. Megatron-core supports 'selective'
    # activation checkpointing where the submodules set in --recompute-modules is
    # checkpointed. The default is "core_attn" which is the memory intensive part of
    # attention. These memory intensive activations are also less compute intensive which
    # makes activation checkpointing more efficient for LLMs (20B+). See Reducing Activation
    # Recomputation in Large Transformer Models (https://arxiv.org/abs/2205.05198) for more
    # details. 'full' will checkpoint the entire transformer layer. If None, no recompute is
    # performed and all activations are saved. If set, must be 'selective' or 'full'.
    # 'selective' always uses all layers.
    recompute_granularity: Literal['full', 'selective'] | None = None

    # Determines which transformer layers will be recomputed. uniform will uniformly divide
    # the total number of transformer layers in a transformer block and recompute the input
    # activation of each divided chunk at the specified granularity. block will recompute the
    # input activations for only a set number of transformer layers per pipeline stage. The
    # rest of the layers in the pipeline stage will not have any activations recomputed. If
    # None, and recompute is enabled, all layers will do recomputation. If set, must be
    # 'uniform' or 'block'.
    recompute_method: Literal['uniform', 'block'] | None = None

    # When recompute_method is uniform, recompute_num_layers is the number of transformer
    # layers in each uniformly divided recompute unit. When recompute_method is block,
    # recompute_num_layers is the number of transformer layers to recompute within each
    # pipeline stage. Must be None for 'selective' activation checkpointing.
    recompute_num_layers: int | None = None

    # If True, distribute recomputed activations across the model parallel group.
    distribute_saved_activations: bool = False

    # The submodules to recompute. choices: "core_attn", "moe_act", "layernorm",
    # "mla_up_proj", "mlp", "moe", "shared_experts". default: ["core_attn"]. "core_attn":
    # recompute the core attention part of the transformer layer. "moe_act": recompute the MoE
    # MLP activation function. "layernorm": recompute the input_layernorm and
    # pre_mlp_layernorm. "mla_up_proj": recompute the MLA up projection and RoPE applying
    # parts. "mlp": recompute the dense MLP submodule. "moe": recompute the MoE layer.
    # "shared_experts": recompute the shared experts in the MoE layer. "moe_act", "layernorm",
    # and "mla_up_proj" use output-discarding checkpointing, "core_attn", "mlp", "moe", and
    # "shared_experts" use normal checkpointing.
    recompute_modules: list[str] | None = None

    # If set, enables the use of FP8 precision through Transformer Engine. There are 2
    # predefined choices (1) 'e4m3' uniformly uses e4m3 for all FP8 tensors, (2) 'hybrid' uses
    # e4m3 for all FP8 activation and weight tensors and e5m2 for all FP8 output activation
    # gradient tensors.
    fp8: Literal['e4m3', 'hybrid'] | None = None

    # If set, enables the use of FP8 precision through Transformer Engine. There are 5
    # predefined choices (1) 'tensorwise' uses per tensor current scaling recipe, (2)
    # 'delayed' uses delayed scaling recipe, 3) 'mxfp8' for Blackwell architecture only, 4)
    # 'blockwise' for blockwise scaling recipe, 5) 'custom' for custom quantization recipe.
    fp8_recipe: Literal['tensorwise', 'delayed', 'mxfp8', 'blockwise', 'custom'] = 'delayed'

    # Python import path to a callable quantizer factory, e.g.,
    # package.module.quantizer_factory. Required when fp8_recipe is custom.
    fp8_quantizer_factory: str | None = None

    # Margin for the scaling factor computation.
    fp8_margin: int = 0

    # DEPRECATED from TransformerEngine v1.8.0. This flag is ignored. Controls how often the
    # scaling factor is recomputed.
    fp8_interval: int = 1

    # The length of the amax history window used for scaling factor computation.
    fp8_amax_history_len: int = 1

    # Algorithm used for choosing the `amax` value for the scaling factor computation. There
    # are 2 predefined choices: `max` chooses the largest `amax` in the history window, while
    # `most_recent` always chooses the most recently seen value.
    fp8_amax_compute_algo: Literal['most_recent', 'max'] = 'most_recent'

    # When set to False, override FP8 config options and do the wgrad computation in higher
    # precision.
    fp8_wgrad: bool = True

    # If True, retains first and last N TransformerBlocks in BF16 as opposed to FP8.
    first_last_layers_bf16: bool = False

    # Number of layers at the start of the model to keep in BF16 precision when
    # first_last_layers_bf16 is True.
    num_layers_at_start_in_bf16: int = 1

    # Number of layers at the end of the model to keep in BF16 precision when
    # first_last_layers_bf16 is True.
    num_layers_at_end_in_bf16: int = 1

    # Use the kitchen extension for attention (instead of TE's attention).
    use_kitchen_attention: bool = False

    # Which kitchen attention backend to use when use_kitchen_attention=True. "sdpa" for
    # KitchenDotProductAttention, "fa" for KitchenFlashAttention.
    kitchen_attention_backend: Literal['sdpa', 'fa'] = 'sdpa'

    # If set, enables the use of FP4 precision through Transformer Engine. Currently only
    # supports 'nvfp4' which uses NVFP4BlockScaling recipe (requires TE >= 2.7.0.dev0).
    fp4: Literal['e2m1'] | None = None

    # If set, enables the use of FP4 precision through Transformer Engine. Currently only
    # 'nvfp4' is supported which uses NVFP4BlockScaling recipe for Blackwell+ architecture.
    fp4_recipe: Literal['nvfp4', 'custom'] = 'nvfp4'

    # Python import path to a callable quantizer factory, e.g.,
    # package.module.quantizer_factory. Required when fp4_recipe is custom.
    fp4_quantizer_factory: str | None = None

    # Shared expert total ffn hidden size. It should be equal to 'num_shared_experts *
    # ffn_size_of_each_shared_expert' if there are multiple shared experts. None means no
    # shared expert. By default, the shared experts execute before the router. However, when
    # moe_shared_expert_overlap or overlap_moe_expert_parallel_comm is set, the shared experts
    # execute after the router, before the routed experts. This makes the gradients from the
    # router and the shared experts added in different orders to the hidden_states, causing
    # minor numerical differences in the hidden_states gradient.
    moe_shared_expert_intermediate_size: int | None = None

    # Enable gate for shared expert. Only effective when moe-shared-expert-intermediate-size
    # is set.
    moe_shared_expert_gate: bool = False

    # Enable overlapping between shared expert computations and dispatcher communications.
    # Without this, the shared experts execute before the router. Only effective when moe-
    # shared-expert-intermediate-size is set.
    moe_shared_expert_overlap: bool = False

    # MoE Feed-Forward Network hidden size. If not specified, defaults to the ffn_hidden_size.
    moe_ffn_hidden_size: int | None = None

    # Number of experts to route to for each token.
    moe_router_topk: int = 2

    # If True, enable the routing replay feature for MoE layers.
    moe_enable_routing_replay: bool = False

    # Whether to pad the routing_map to make sure the number of tokens each expert receives is
    # a multiple of 16/32 for quantized precision (e.g., FP8, FP4). This can remove the
    # explicit padding in the GroupedMLP layer.
    moe_router_padding_for_quantization: bool = False

    # [Compatibility alias for moe_router_padding_for_quantization] Enabling this will also
    # enable moe_router_padding_for_quantization.
    moe_router_padding_for_fp8: bool = False

    # Number of groups to divide experts into for group-limited routing. When using group-
    # limited routing: 1. Experts are divided into 'moe_router_num_groups' equal-sized groups
    # 2. For each token, 'moe_router_group_topk' groups are selected based on sum of
    # top-('moe_router_topk'/'moe_router_group_topk') routing scores within each group 3. From
    # these selected groups, 'moe_router_topk' individual experts are chosen Two common use
    # cases: - Device-limited routing: Set 'moe_router_num_groups' equal to expert parallel
    # size (EP) to limit each token to experts on a subset of devices (See DeepSeek-V2:
    # https://arxiv.org/pdf/2405.04434) - Node-limited routing: Set 'moe_router_num_groups'
    # equal to number of nodes in EP group to limit each token to experts on a subset of nodes
    # (See DeepSeek-V3: https://arxiv.org/pdf/2412.19437)
    moe_router_num_groups: int | None = None

    # Number of selected groups for group-limited routing.
    moe_router_group_topk: int | None = None

    # Enable pre-softmax(pre-sigmoid) routing for MoE, which means softmax is before the top-k
    # selection. By default, softmax is done after top-k.
    moe_router_pre_softmax: bool = False

    # Scaling factor for routing score in top-k selection, only works when
    # moe_router_pre_softmax enabled. Defaults to None, which means no scaling.
    moe_router_topk_scaling_factor: float | None = None

    # Score function for MoE routing. Can be "softmax", "sigmoid" or "sqrtsoftplus".
    moe_router_score_function: Literal['softmax', 'sigmoid', 'sqrtsoftplus'] = 'softmax'

    # Data type for routing and expert output weighted averaging. Using fp32 or fp64 can
    # improve stability especially when the number of experts is large (e.g. finegrained-moe).
    # None means no changes for dtype.
    moe_router_dtype: Literal['fp32', 'fp64'] | None = None

    # TopK routing with dynamic per-expert bias in the aux-loss-free load balancing strategy.
    # The routing decision is based on the sum of the routing scores and the expert bias. See
    # https://arxiv.org/abs/2408.15664 for details.
    moe_router_enable_expert_bias: bool = False

    # The expert bias is updated based on the number of assigned tokens to each expert in a
    # global batch, where the bias is increased for the experts with less assigned tokens and
    # decreased for the experts with more assigned tokens. The default value 1e-3 is same as
    # that used in DeepSeekV3.
    moe_router_bias_update_rate: float = 0.001

    # [Experimental] Force load balancing with random logits for MoE router, supports naive
    # topk and group-limited topk. This is an experimental feature and only for benchmark.
    moe_router_force_load_balancing: bool = False

    # Apply random expert bias in normal distribution with specified std to router logits.
    # Shared seed across all ranks ensures identical bias. If positive, generates new random
    # bias each forward pass. If negative, generates bias once per layer and reuses it (abs
    # value is std). This is an experimental feature for benchmarking purposes.
    moe_router_force_biased: float | None = None

