    # iteration excluding optimizer) is enabled. --cuda-graph-scope determines the scope of
    # graph capture.
    enable_cuda_graph: bool = False

    # Number of warmup steps for CUDA graphs
    cuda_graph_warmup_steps: int = 3

    # DEPRECATED and replaced by cuda_graph_impl. When set to true, TransformerLayer layers
    # are swapped with user provided CUDA graphs.
    external_cuda_graph: bool = False

    # Determines the CUDA graph capture implementation. "none": no CUDA graph. "local":
    # capture the CUDA graph using MCore local implementation. Either partial CUDA graph
    # (1/many CUDA graph per layer) or full iteration CUDA graph (1 CUDA graph for whole
    # iteration excluding optimizer) is enabled. "transformer_engine": capture the CUDA graph
    # using TE make_graphed_callables().
    cuda_graph_impl: Literal['none', 'local', 'transformer_engine'] = 'none'

    # When set to True, clone the output of scatter_to_sequence_parallel_region in embedding
