    # normalization in the attention part. "qkv_linear": offload the input of the qkv linear
    # part. "core_attn": offload the input of the core attention part. "attn_proj": offload
    # the input of the attn linear projection part. "mlp_norm": offload the input of the
    # normalization in the mlp part. "expert_fc1": offload the input of the expert fc1 part.
    # "moe_act": offload the input of the moe act part.
    offload_modules: list[str] = field(default_factory=lambda: [])

